// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十一點三十分。禮堂的燈全部亮著，白色的日光燈管和暖黃色的舞台聚光燈同時運作，把整個空間照得沒有一絲陰影。座位區坐了大約七成滿——大部分是學生和留校過夜的家長，少數是穿著反光背心的志工和幾個扛著攝影設備的媒體人員。空氣裡混著潮濕的外套味道和人體蒸出來的熱氣，悶而暖，像一個被塞了太多人的罐頭。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舞台上的大螢幕正在測試直播訊號。畫面閃了幾下，跳出一行字：「鳴海高中百年校慶閉幕典禮——直播測試中」。字很大，白底藍字，每個筆劃都銳利得像刻出來的。畫面又閃了一下，切到了一個空鏡頭——雨夜的校園，遠處的鐘樓在雨幕後面只剩一個模糊的輪廓，像一個正在消失的影子。三秒後畫面切回測試卡。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "閉幕典禮因為天氣提前了。原定十點的戶外煙火表演取消，所有的節目壓縮到室內進行，時間表被裁得七零八落。舞台側邊有人正在對講機裡爭論順序問題，聲音壓得很低但語速很快，像兩條交纏的蛇。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)直播。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果今晚的閉幕典禮全程直播，那任何在校園裡發生的事，理論上都有可能被某台攝影機拍到。也有可能不會。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他坐在禮堂倒數第三排靠走道的座位上。這個位置是他選的——背對牆壁，面對舞台，走道在右手邊，左邊是空的座位。隨時可以起身，隨時可以離開，不需要越過任何人。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手插進外套口袋裡，右手的指尖碰到了手機，左手的指尖碰到了——", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)什麼東西？", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手指停住了。口袋左邊，靠近內襯接縫的位置，有一張紙。薄的，硬的，邊緣整齊，像一張被折過又攤平的照片。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這不是我的東西。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我今天穿的是同一件外套。早上出門前我摸過口袋，裡面只有衛生紙和手機。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這是什麼時候被放進來的？", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有立刻掏出來。他的手停留在口袋裡，指尖按在那張紙的邊緣上，感受它的質地。光滑的表面，輕微的凹凸——影印紙的質感，不是原版相紙。他的拇指在紙面上滑了一下，感覺到一個角是折過的。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他用餘光掃了一圈周圍。左邊的空位沒有人。右邊走道對面的座位上坐著一個中年家長，正在滑手機。前排的人在聊天。後排的人在打瞌睡。沒有人看他。沒有人在注意他。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)什麼時候？我今天的路線——宿舍、餐廳、校史館、校門口、長廊、教學樓、走廊、禮堂。在禮堂裡我坐著沒動過。之前在走廊上也沒有和任何人有過身體接觸。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)除非是在人群中的某一刻。某個人經過我身邊的時候。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他慢慢地把那張紙從口袋裡抽出來。動作很小，手指捏著紙的邊緣，藏在掌心裡，不讓旁邊的人看到。他低頭看了一眼。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是一張照片的影印本。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這張照片。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我見過這張照片。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "今天早上在校史館。他在舊檔案盒裡翻到的那些照片裡，有一張——四個人站在大榕樹下，舊校門前。他的父親、邵叔、一個他不認識的男人，和一個他不認識的女人。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "影印件的畫質比原版粗糙很多，顆粒感明顯，對比度被影印機拉高了，所有人的臉都變得黑白分明，像木刻版畫。但人物的位置、姿勢、背景，全部一模一樣。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有一個地方不一樣。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯不對。少了什麼。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把照片舉近了一點，瞇著眼看。父親還在，抱著小時候的他，笑容一模一樣。邵叔還在，手裡的扳手、白牙、笑容，一模一樣。那個他不認識的男人也還在，側身躲避鏡頭的姿勢一模一樣。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四個人不在了。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那個女人。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "照片中間的位置，原本站著那個穿淺灰色外套、低馬尾、表情淡漠的女人的地方——被裁掉了。不是用筆塗掉的那種，是用剪刀沿著她的輪廓邊緣整齊地剪去了。裁切的手法很乾淨，線條直而穩定，不像臨時起意，像是有準備地、有目的地把那個人從畫面中移除。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她的臉被剪掉了。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是遮住，不是打碼，是直接從這張照片裡消失。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)為什麼？她到底是誰？為什麼有人要把她從照片裡裁掉，然後把剩下的部分放進我的口袋？", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他翻到背面。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "背面有字。手寫的，藍色原子筆，字跡不大，但很清楚。不是印刷體的工整，是一個人習慣了快速書寫的流暢——筆劃之間的連接很自然，沒有猶豫的痕跡，像是一口氣寫完的。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「你爸留下的東西，在鐘樓。22:20。」", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手指收緊了。照片的邊角被他的指甲掐住，紙面發出輕微的摺痕聲。他沒有感覺到。他的注意力全部集中在那行字上，像一束光被聚焦在了一個針尖大小的點上。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)爸留下的東西。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我爸還有東西留下？", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)火災之後，我們家的東西幾乎全燒了。衣物、家具、書本、照片——全部變成了灰。保險公司來人估損的時候，清單上寫的是「全損」，兩個字就概括了我爸四十年人生裡積累的所有物品。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他怎麼可能還有東西留下？在哪裡留下？為什麼是在鐘樓？", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他盯著那行字看了很久。久到前排的節目已經換了兩個，舞台上的主持人正在介紹一個校友合唱團。掌聲響起來又落下。他都沒有聽到。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)22:20。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)早上那條訊息的時間是22:22。這張紙上寫的是22:20。差兩分鐘。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)早上那條訊息說「鐘樓」。許星棠說「不要靠近鐘樓」。現在這張紙也說「鐘樓」。三個不同的來源，指向同一個地點。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)早上那條訊息要我「去」。許星棠要我「不要去」。這張紙要我「去」。兩個叫我來，一個叫我不要來。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)問題是，那一個叫我不要來的人，是我今天唯一當面說過話的。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把照片翻回正面，再次看著父親的臉。影印件把所有的色彩都剝掉了，只剩黑和白。父親的笑容在黑白之間變得更銳利，也更遙遠，像隔著一層磨砂玻璃。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)你在笑。你抱著我，你在笑。你看上去像一個普通的父親，過著普通的日子。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)然後你就變成了新聞裡的那張臉。那張臉上沒有笑容，只有空洞的眼神和被裁切過的邊緣，像一個已經被定了罪的人。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十年了。我一直告訴自己，我不在乎。我不在乎你是不是被冤枉的，不在乎真相是什麼，不在乎別人怎麼說。你不在了，這是唯一確定的事。其他的，和我無關。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但我的手在抖。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低頭看了一眼自己的手。確實在抖。不明顯，拿著照片的手指指尖有很細的顫動，頻率很快，像琴弦被撥動後的餘震。他用另一隻手按住，壓了兩秒，鬆開，還是抖。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我在乎。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/trembling" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我一直都他媽的在乎。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/trembling" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我不在乎誰發了這張紙、誰裁掉了那個女人、誰知道我爸還有東西留下。我在乎的只有一件事：我爸是不是真的留下了什麼。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果他留下了什麼——一封信、一句話、一樣東西——那他離開之前，在想的是什麼？", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在想我嗎？", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把照片塞回口袋裡。動作比拿出來的時候快很多，帶著一種不願意繼續看的急躁。他靠在椅背上，仰頭看著禮堂的天花板。天花板上有很多管道和線纜，交錯縱橫，像一幅沒有邏輯的抽象畫。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)許星棠叫我不要去。她說「今天不要靠近鐘樓」的時候，語氣很平，像在說一件確定會發生的事，不是在勸我。她知道什麼。她知道鐘樓那裡有什麼，或者會發生什麼。她在警告我。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但這張照片不是警告。這是一張誘餌。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)有人在用我爸當餌。他們知道我爸是我最脆弱的地方。他們知道我可以在乎所有人的眼光、可以在所有議論裡保持沉默、可以把所有的好奇心都壓下去——除了關於我爸的。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們知道了。所以他們把這張照片放進我的口袋。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的後腦勺抵在椅背上，眼睛盯著天花板的管道。周圍的聲音像隔了一層水——掌聲、音樂、主持人說話的聲音、座椅彈簧的嘎吱聲——全部變得模糊而遙遠。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我知道這是一個陷阱。我從看到那行字的時候就知道。你用我爸來釣我，太精準了。精準到讓我懷疑，設計這個陷阱的人是不是也失去過什麼人，所以才能理解這種失去的形狀。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但知道是陷阱，不代表我不會走進去。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)因為如果這不是陷阱呢？如果我爸真的在鐘樓裡留下了什麼？哪怕只有百分之一的可能是真的——我也要知道。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他坐直了身體。目光重新落回禮堂裡。人比剛才更多了，後排站著的人開始往兩側溢出來。有人在拍照，有人在低聲討論直播的畫質，有人在往舞台上遞道具。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看到了許星棠。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在禮堂右側的走道上，靠側門的位置。又拿著相機。和下午在長廊上一樣的姿勢——相機舉到眼前，身體微微前傾。但她的鏡頭不是對著舞台。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她又在拍不該拍的東西。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的鏡頭朝向側門的方向——那裡有一張臨時搭建的摺疊桌，桌上放著對講機和文件夾，桌後面站著一個穿制服的警察。那是臨時指揮區在禮堂裡的分站。她的鏡頭在那個方向停留了大約五秒，然後她放下相機，轉頭朝另一個方向看了一眼。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她在觀察。她不是在記錄校慶。她在記錄人。準確地說，她在記錄某些人的行動路線。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他正想站起來，許星棠動了。她把相機背帶甩到肩後，低頭穿過走道上的人群，朝禮堂的側門走去。她的速度不快，但方向很明確，身體在人群之間側身穿行，像一條魚在水草裡游動。然後她消失在側門外面。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她出了側門。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)側門外面是禮堂後台的走廊，走廊盡頭是通往校園北區的小路。校園北區——鐘樓所在的方向。", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她也在往那個方向去？", background: "chapter_1/ch1_act8_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他開始往走道方向移動。身體先於大腦做出了決定——他還沒有在腦子裡完整地說出「我要去鐘樓」這句話，但他的腳已經開始往走道上邁了。走到側門口的時候，他看到了一個畫面。", background: "chapter_1/ch1_act8_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "側門外面是一段狹窄的走廊，走廊兩邊是後台的休息室和設備間。走廊盡頭有一扇通往外面的鐵門，鐵門是半開的，雨水從門縫裡斜斜地打進來，在地面上畫出一道濕痕。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐵門外面，雨幕之中，有一個人影。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個人影穿著一件黑色的雨衣。雨衣很大，帽子的邊緣壓得很低，遮住了大半張臉。身形看不清楚——雨衣太寬鬆了，分不出男女，分不出高矮。雨衣的下擺被風吹得貼在腿上，又彈開來，像一面黑色的旗。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)雨衣。今天一整天沒有人穿雨衣。所有人都撐傘或者淋雨。雨衣太顯眼了。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個人影正在走。走的方向是遠離禮堂、遠離人群、遠離所有燈光的方向。朝著校園的北邊。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓的方向。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看到了一個細節。那個人影的右肩上，有一條背帶。黑色的，窄的，從肩膀斜跨到腰側。背帶的末端連接著一個被雨衣下擺遮住大半的長方形物體。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)相機背帶。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那是一台相機。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)黑色雨衣，相機——是許星棠？", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不。她的身形比這個人影窄。而且她剛才是從側門出去的，時間上來得及換一件雨衣，但她的相機背帶是灰色的，這個是黑色的。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是她。那是誰？", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個人影在雨幕裡越走越遠。走廊盡頭的鐵門框住了那個背影，像一幅被雨水浸泡的畫——黑色的雨衣、灰色的雨幕、遠處模糊的建築輪廓。人影沒有回頭。走得很快，但沒有跑，像一個知道自己要去哪裡的人。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們也往鐘樓去了。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)黑色雨衣、相機、鐘樓。這是那條訊息裡說的「相機」嗎？如果是，那穿雨衣的人是在把那台相機帶到鐘樓去。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)或者這是一個偽裝。一個穿著雨衣、背著相機的人故意出現在這裡，讓我以為那就是訊息裡說的東西，引我過去。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在走廊裡，雨水從半開的鐵門飛進來，打在他的手臂上。冰涼的。和口袋裡那張照片的觸感形成了兩種完全不同的溫度——一種是冷的，一種是燙的。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)許星棠叫我不要去。但我口袋裡的這張紙叫我過去。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一個我不認識的人——或者是認識但不願意承認的人——用我爸的照片、用我爸的字跡風格、用我爸這張永遠不會出現在新聞裡的笑臉，告訴我：你爸留下了東西，在鐘樓等你。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她們都說不要去。她們說得對。這是陷阱，我知道。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但我爸在裡面。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不管那是不是真的「我爸留下的東西」，只要它和十年前那場火有關，和那張被裁掉一半的照片有關，和「相機」這個詞有關——我就一定要知道。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他深吸了一口氣。走廊裡的空氣帶著雨水和鐵鏽的味道，吸進去冰涼，在胸腔裡轉了一圈，出來的時候變成了白色的霧。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)三個理由。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一。這張紙說我爸在鐘樓裡留下了東西。也許是假的。但如果有一絲可能是真的，我不可能不去。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第二。那個黑色雨衣的人帶著一台相機，正在往鐘樓的方向走。早上那條訊息提到了「相機」。如果那台相機和訊息有關，那它現在正在被帶到它應該在的地方。我要看到那台相機。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第三。許星棠也可能往那個方向去了。她今天拍了指揮室、拍了邵叔和林主任、現在又拍了禮堂的臨時指揮區。她知道太多。她要嘛是那個發出警告的人，要嘛是設下陷阱的人。不管是哪一個，我需要答案。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)三個理由。任何一個都夠了。三個加在一起，我沒有理由不去。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走向鐵門。手放在門把上，金屬的觸感冷而濕，像握住了一塊冰。他推開門，雨聲瞬間灌進耳朵——不是禮堂裡那種被牆壁過濾過的、悶悶的雨聲，而是直接的、粗暴的、從天上砸下來的水的重量。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色雨衣的人影已經消失在雨幕裡了。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)22:20。還有不到一小時。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他踏進雨裡。雨水在三秒之內浸透了他的外套肩部，順著衣領流進脖頸，冰涼的水線沿著脊椎向下滑。他沒有低頭，沒有縮肩，沒有做出任何躲避雨水的動作。他只是走。朝著鐘樓的方向。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓，我來了。", background: "chapter_1/ch1_act8_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身後，禮堂的門還開著。裡面傳出主持人的聲音，被雨聲切割成碎片：「⋯⋯百年鳴海⋯⋯感謝⋯⋯直播將在⋯⋯」舞台上的大螢幕還亮著，測試畫面裡的鐘樓輪廓一閃而過，像一個預兆。", background: "chapter_1/ch1_act8_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那座在雨夜裡沉默了十年的灰色建築，此刻正等在黑暗的盡頭，像一個不會說話的證人。它不會回答任何問題，但它一直在那裡。十年前在那裡，十年後還在那裡。指針在雨幕後面看不見的地方走著，一步一步，朝向二十二點二十分。", background: "chapter_1/ch1_act8_s1" },
];
